import{_ as t,o as a,c as o,ag as r}from"./chunks/framework.NIzFHKo_.js";const g=JSON.parse('{"title":"QiLabs Content Templates","description":"","frontmatter":{},"headers":[],"relativePath":"10_core/70_assets/templates/readme.md","filePath":"10_core/70_assets/templates/readme.md"}'),s={name:"10_core/70_assets/templates/readme.md"};function n(d,e,i,l,c,m){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="qilabs-content-templates" tabindex="-1">QiLabs Content Templates <a class="header-anchor" href="#qilabs-content-templates" aria-label="Permalink to &quot;QiLabs Content Templates&quot;">​</a></h1><p>This directory contains the canonical templates for generating Markdown content across the QiLabs ecosystem. These templates enforce consistent metadata and structural rules to prevent drift and ensure machine-readability by ingestion pipelines (QiArchive).</p><h2 id="available-templates" tabindex="-1">Available Templates <a class="header-anchor" href="#available-templates" aria-label="Permalink to &quot;Available Templates&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Template</th><th>Purpose</th><th>When to use</th></tr></thead><tbody><tr><td><strong><code>note_template.md</code></strong></td><td>Generic knowledge, thoughts, meeting notes</td><td>Creating a new note in Obsidian or the knowledge base.</td></tr><tr><td><strong><code>artifact_template.md</code></strong></td><td>System outputs, plans, walkthroughs, generated code logs</td><td>When an AI agent or automated script generates a durable record of a task or plan.</td></tr><tr><td><strong><code>adr_template.md</code></strong></td><td>Architecture Decision Records</td><td>When formalizing a new system rule, schema change, or structural mandate.</td></tr></tbody></table><h2 id="metadata-standard-frontmatter" tabindex="-1">Metadata Standard (Frontmatter) <a class="header-anchor" href="#metadata-standard-frontmatter" aria-label="Permalink to &quot;Metadata Standard (Frontmatter)&quot;">​</a></h2><p>All templates use YAML frontmatter that aligns with the QiOS Master Blueprint metadata rules:</p><ul><li><strong><code>id</code></strong>: A unique UUID or ULID.</li><li><strong><code>short_code</code></strong>: A human-friendly identifier (e.g., <code>QXXXXXX</code>).</li><li><strong><code>domain_prefix</code></strong>: The system domain this file belongs to (e.g., <code>bbr4821</code> for the main tenant, <code>qiarchive</code> for ingestion, <code>qicase</code> for legal/cases).</li><li><strong><code>document_type</code></strong>: Enforces strict categorization (note, artifact, adr).</li><li><strong><code>status</code></strong>: The lifecycle stage of the document (draft, active, archived).</li><li><strong><code>tags</code></strong>: Used by the embedding system for semantic clustering.</li></ul><p>By strictly adhering to these YAML fields, local workers (like <code>qiarchive</code>) can parse, categorize, and index the entire repository without guessing.</p>',8)])])}const p=t(s,[["render",n]]);export{g as __pageData,p as default};
